class Solution:
    def reorderedPowerOf2(self, n: int) -> bool:
        s = str(n)
        sorted_n = sorted(s)
        for i in range(31):
            power = 2 ** i
            power_str = str(power)
            if len(power_str) != len(s):
                continue
            if sorted(power_str) == sorted_n:
                return True
        return False

